+    if (comptime has_avx2) {
+        return "AVX2 (x86_64, 32-byte vectors)";
+    } else if (comptime has_sse2) {
+        return "SSE2 (x86_64, 16-byte vectors)";
+    } else if (comptime is_aarch64) {
+        return "NEON (ARM64/M1, 16-byte vectors)";
+    }
+    return "Scalar (no SIMD)";
+}
